"""
Parameterized generator for GH909_pymc_7501.

Source PR:    https://github.com/pymc-devs/pymc/pull/7501
Source Issue: https://github.com/pymc-devs/pymc/issues/6508

Seed varies: renames 'alpha' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH909_pymc_7501'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH909_pymc_7501'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('alpha', 'alpha' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH909_pymc_7501',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'pymc-devs/pymc',
                "pr_number": 7501,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/pymc-devs/pymc/pull/7501",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'pymc/printing.py': '#   Copyright 2024 The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\n\n\nfrom functools import partial\n\nfrom pytensor.compile import SharedVariable\nfrom pytensor.graph.basic import Constant, walk\nfrom pytensor.tensor.basic import TensorVariable, Variable\nfrom pytensor.tensor.elemwise import DimShuffle\nfrom pytensor.tensor.random.basic import RandomVariable\nfrom pytensor.tensor.random.type import RandomType\nfrom pytensor.tensor.type_other import NoneTypeT\n\nfrom pymc.model import Model\n\n__all__ = [\n    "str_for_dist",\n    "str_for_model",\n    "str_for_potential_or_deterministic",\n]\n\n\ndef str_for_dist(\n    dist: TensorVariable, formatting: str = "plain", include_params: bool = True\n) -> str:\n    """Make a human-readable string representation of a Distribution in a model, either\n    LaTeX or plain, optionally with distribution parameter values included."""\n\n    if include_params:\n        if isinstance(dist.owner.op, RandomVariable) or getattr(\n            dist.owner.op, "extended_signature", None\n        ):\n            dist_args = [\n                _str_for_input_var(x, formatting=formatting)\n                for x in dist.owner.op.dist_params(dist.owner)\n            ]\n        else:\n            dist_args = [\n                _str_for_input_var(x, formatting=formatting)\n                for x in dist.owner.inputs\n                if not isinstance(x.type, RandomType | NoneTypeT)\n            ]\n\n    print_name = dist.name\n\n    if "latex" in formatting:\n        if print_name is not None:\n            print_name = r"\\text{" + _latex_escape(print_name.strip("$")) + "}"\n\n        op_name = (\n            dist.owner.op._print_name[1]\n            if hasattr(dist.owner.op, "_print_name")\n            else r"\\\\operatorname{Unknown}"\n        )\n        if include_params:\n            params = ",~".join([d.strip("$") for d in dist_args])\n            if print_name:\n                return rf"${print_name} \\sim {op_name}({params})$"\n            else:\n                return rf"${op_name}({params})$"\n\n        else:\n            if print_name:\n                return rf"${print_name} \\sim {op_name}$"\n            else:\n                return rf"${op_name}$"\n\n    else:  # plain\n        dist_name = (\n            dist.owner.op._print_name[0] if hasattr(dist.owner.op, "_print_name") else "Unknown"\n        )\n        if include_params:\n            params = ", ".join(dist_args)\n            if print_name:\n                return rf"{print_name} ~ {dist_name}({params})"\n            else:\n                return rf"{dist_name}({params})"\n        else:\n            if print_name:\n                return rf"{print_name} ~ {dist_name}"\n            else:\n                return dist_name\n\n\ndef str_for_model(model: Model, formatting: str = "plain", include_params: bool = True) -> str:\n    """Make a human-readable string representation of Model, listing all random variables\n    and their distributions, optionally including parameter values."""\n\n    # Wrap functions to avoid confusing typecheckers\n    sfd = partial(str_for_dist, formatting=formatting, include_params=include_params)\n    sfp = partial(\n        str_for_potential_or_deterministic, formatting=formatting, include_params=include_params\n    )\n\n    free_rv_reprs = [sfd(dist) for dist in model.free_RVs]\n    observed_rv_reprs = [sfd(rv) for rv in model.observed_RVs]\n    det_reprs = [sfp(dist, dist_name="Deterministic") for dist in model.deterministics]\n    potential_reprs = [sfp(pot, dist_name="Potential") for pot in model.potentials]\n\n    var_reprs = free_rv_reprs + det_reprs + observed_rv_reprs + potential_reprs\n\n    if not var_reprs:\n        return ""\n    if "latex" in formatting:\n        var_reprs = [\n            var_repr.replace(r"\\sim", r"&\\sim &").strip("$")\n            for var_repr in var_reprs\n            if var_repr is not None\n        ]\n        return r"""$$\n            \\begin{{array}}{{rcl}}\n            {}\n            \\end{{array}}\n            $$""".format("\\\\\\\\".join(var_reprs))\n    else:\n        # align vars on their ~\n        names = [s[: s.index("~") - 1] for s in var_reprs]\n        distrs = [s[s.index("~") + 2 :] for s in var_reprs]\n        maxlen = str(max(len(x) for x in names))\n        var_reprs = [\n            ("{name:>" + maxlen + "} ~ {distr}").format(name=n, distr=d)\n            for n, d in zip(names, distrs)\n        ]\n        return "\\n".join(var_reprs)\n\n\ndef str_for_potential_or_deterministic(\n    var: TensorVariable,\n    formatting: str = "plain",\n    include_params: bool = True,\n    dist_name: str = "Deterministic",\n) -> str:\n    """Make a human-readable string representation of a Deterministic or Potential in a model, either\n    LaTeX or plain, optionally with distribution parameter values included."""\n    print_name = var.name if var.name is not None else "<unnamed>"\n    if "latex" in formatting:\n        print_name = r"\\text{" + _latex_escape(print_name.strip("$")) + "}"\n        if include_params:\n            return rf"${print_name} \\sim \\operatorname{{{dist_name}}}({_str_for_expression(var, formatting=formatting)})$"\n        else:\n            return rf"${print_name} \\sim \\operatorname{{{dist_name}}}$"\n    else:  # plain\n        if include_params:\n            return rf"{print_name} ~ {dist_name}({_str_for_expression(var, formatting=formatting)})"\n        else:\n            return rf"{print_name} ~ {dist_name}"\n\n\ndef _str_for_input_var(var: Variable, formatting: str) -> str:\n    # Avoid circular import\n    from pymc.distributions.distribution import SymbolicRandomVariable\n\n    def _is_potential_or_deterministic(var: Variable) -> bool:\n        if not hasattr(var, "str_repr"):\n            return False\n        try:\n            return var.str_repr.__func__.func is str_for_potential_or_deterministic\n        except AttributeError:\n            # in case other code overrides str_repr, fallback\n            return False\n\n    if isinstance(var, Constant | SharedVariable):\n        return _str_for_constant(var, formatting)\n    elif isinstance(\n        var.owner.op, RandomVariable | SymbolicRandomVariable\n    ) or _is_potential_or_deterministic(var):\n        # show the names for RandomVariables, Deterministics, and Potentials, rather\n        # than the full expression\n        assert isinstance(var, TensorVariable)\n        return _str_for_input_rv(var, formatting)\n    elif isinstance(var.owner.op, DimShuffle):\n        return _str_for_input_var(var.owner.inputs[0], formatting)\n    else:\n        return _str_for_expression(var, formatting)\n\n\ndef _str_for_input_rv(var: TensorVariable, formatting: str) -> str:\n    _str = (\n        var.name\n        if var.name is not None\n        else str_for_dist(var, formatting=formatting, include_params=True)\n    )\n    if "latex" in formatting:\n        return _latex_text_format(_latex_escape(_str.strip("$")))\n    else:\n        return _str\n\n\ndef _str_for_constant(var: Constant | SharedVariable, formatting: str) -> str:\n    if isinstance(var, Constant):\n        var_data = var.data\n        var_type = "constant"\n    else:\n        var_data = var.get_value()\n        var_type = "shared"\n\n    if len(var_data.shape) == 0:\n        return f"{var_data:.3g}"\n    elif len(var_data.shape) == 1 and var_data.shape[0] == 1:\n        return f"{var_data[0]:.3g}"\n    elif "latex" in formatting:\n        return rf"\\text{{<{var_type}>}}"\n    else:\n        return rf"<{var_type}>"\n\n\ndef _str_for_expression(var: Variable, formatting: str) -> str:\n    # Avoid circular import\n    from pymc.distributions.distribution import SymbolicRandomVariable\n\n    # construct a string like f(a1, ..., aN) listing all random variables a as arguments\n    def _expand(x):\n        if x.owner and (not isinstance(x.owner.op, RandomVariable | SymbolicRandomVariable)):\n            return reversed(x.owner.inputs)\n\n    parents = []\n    names = []\n    for x in walk(nodes=var.owner.inputs, expand=_expand):\n        assert isinstance(x, Variable)\n        if x.owner and isinstance(x.owner.op, RandomVariable | SymbolicRandomVariable):\n            parents.append(x)\n            xname = x.name\n            if xname is None:\n                # If the variable is unnamed, we show the op\'s name as we do\n                # with constants\n                opname = x.owner.op.name\n                if opname is not None:\n                    xname = rf"<{opname}>"\n            assert xname is not None\n            names.append(xname)\n\n    if "latex" in formatting:\n        return (\n            r"f("\n            + ",~".join([_latex_text_format(_latex_escape(n.strip("$"))) for n in names])\n            + ")"\n        )\n    else:\n        return r"f(" + ", ".join([n.strip("$") for n in names]) + ")"\n\n\ndef _latex_text_format(text: str) -> str:\n    if r"\\operatorname{" in text:\n        return text\n    else:\n        return r"\\text{" + text + "}"\n\n\ndef _latex_escape(text: str) -> str:\n    # Note that this is *NOT* a proper LaTeX escaper, on purpose. _repr_latex_ is\n    # primarily used in the context of Jupyter notebooks, which render using MathJax.\n    # MathJax is a subset of LaTeX proper, which expects only $ to be escaped. If we were\n    # to also escape e.g. _ (replace with \\_), then "\\_" will show up in the output, etc.\n    return text.replace("$", r"\\$")\n\n\ndef _default_repr_pretty(obj: TensorVariable | Model, p, cycle):\n    """Handy plug-in method to instruct IPython-like REPLs to use our str_repr above."""\n    # we know that our str_repr does not recurse, so we can ignore cycle\n    try:\n        if not hasattr(obj, "str_repr"):\n            raise AttributeError\n        output = obj.str_repr()\n        # Find newlines and replace them with p.break_()\n        # (see IPython.lib.pretty._repr_pprint)\n        lines = output.splitlines()\n        with p.group():\n            for idx, output_line in enumerate(lines):\n                if idx:\n                    p.break_()\n                p.text(output_line)\n    except AttributeError:\n        # the default fallback option (no str_repr method)\n        IPython.lib.pretty._repr_pprint(obj, p, cycle)\n\n\ntry:\n    # register our custom pretty printer in ipython shells\n    import IPython\n\n    IPython.lib.pretty.for_type(TensorVariable, _default_repr_pretty)\n    IPython.lib.pretty.for_type(Model, _default_repr_pretty)\nexcept (ModuleNotFoundError, AttributeError):\n    # no ipython shell\n    pass\n',
            'tests/test_printing.py': '#   Copyright 2024 The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\nimport numpy as np\n\nfrom pytensor.tensor.random import normal\n\nfrom pymc import Bernoulli, Censored, CustomDist, Gamma, HalfCauchy, Mixture, StudentT, Truncated\nfrom pymc.distributions import (\n    Dirichlet,\n    DirichletMultinomial,\n    HalfNormal,\n    KroneckerNormal,\n    MvNormal,\n    NegativeBinomial,\n    Normal,\n    Uniform,\n    ZeroInflatedPoisson,\n)\nfrom pymc.math import dot\nfrom pymc.model import Deterministic, Model, Potential\nfrom pymc.pytensorf import floatX\n\n\nclass BaseTestStrAndLatexRepr:\n    def test__repr_latex_(self):\n        for distribution, tex in zip(self.distributions, self.expected[("latex", True)]):\n            assert distribution._repr_latex_() == tex\n\n        model_tex = self.model._repr_latex_()\n\n        # make sure each variable is in the model\n        for tex in self.expected[("latex", True)]:\n            for segment in tex.strip("$").split(r"\\sim"):\n                assert segment in model_tex\n\n    def test_str_repr(self):\n        for str_format in self.formats:\n            for dist, text in zip(self.distributions, self.expected[str_format]):\n                assert dist.str_repr(*str_format) == text\n\n            model_text = self.model.str_repr(*str_format)\n            for text in self.expected[str_format]:\n                if str_format[0] == "latex":\n                    for segment in text.strip("$").split(r"\\sim"):\n                        assert segment in model_text\n                else:\n                    assert text in model_text\n\n\nclass TestMonolith(BaseTestStrAndLatexRepr):\n    def setup_class(self):\n        # True parameter values\n        alpha, sigma = 1, 1\n        beta = [1, 2.5]\n\n        # Size of dataset\n        size = 100\n\n        # Predictor variable\n        X = np.random.normal(size=(size, 2)).dot(np.array([[1, 0], [0, 0.2]]))\n\n        # Simulate outcome variable\n        Y = alpha + X.dot(beta) + np.random.randn(size) * sigma\n        with Model() as self.model:\n            # TODO: some variables commented out here as they\'re not working properly\n            # in v4 yet (9-jul-2021), so doesn\'t make sense to test str/latex for them\n\n            # Priors for unknown model parameters\n            alpha = Normal("alpha", mu=0, sigma=10)\n            b = Normal("beta", mu=0, sigma=10, size=(2,), observed=beta)\n            sigma = HalfNormal("sigma", sigma=1)\n\n            # Test Cholesky parameterization\n            Z = MvNormal("Z", mu=np.zeros(2), chol=np.eye(2), size=(2,))\n\n            # NegativeBinomial representations to test issue 4186\n            # nb1 = pm.NegativeBinomial(\n            #     "nb_with_mu_alpha", mu=pm.Normal("nbmu"), alpha=pm.Gamma("nbalpha", mu=6, sigma=1)\n            # )\n            nb2 = NegativeBinomial("nb_with_p_n", p=Uniform("nbp"), n=10)\n\n            # SymbolicRV\n            zip = ZeroInflatedPoisson("zip", 0.5, 5)\n\n            # Nested SymbolicRV\n            comp_1 = ZeroInflatedPoisson.dist(0.5, 5)\n            comp_2 = Censored.dist(Bernoulli.dist(0.5), -1, 1)\n            w = Dirichlet("w", [1, 1])\n            nested_mix = Mixture("nested_mix", w, [comp_1, comp_2])\n\n            # Expected value of outcome\n            mu = Deterministic("mu", floatX(alpha + dot(X, b)))\n\n            # KroneckerNormal\n            n, m = 3, 4\n            covs = [np.eye(n), np.eye(m)]\n            kron_normal = KroneckerNormal("kron_normal", mu=np.zeros(n * m), covs=covs, size=n * m)\n\n            # MatrixNormal\n            # matrix_normal = MatrixNormal(\n            #     "mat_normal",\n            #     mu=np.random.normal(size=n),\n            #     rowcov=np.eye(n),\n            #     colchol=np.linalg.cholesky(np.eye(n)),\n            #     size=(n, n),\n            # )\n\n            # DirichletMultinomial\n            dm = DirichletMultinomial("dm", n=5, a=[1, 1, 1], size=(2, 3))\n\n            # Likelihood (sampling distribution) of observations\n            Y_obs = Normal("Y_obs", mu=mu, sigma=sigma, observed=Y)\n\n            # add a potential as well\n            pot = Potential("pot", mu**2)\n\n            # add a deterministic that depends on an unnamed random variable\n            pred = Deterministic("pred", Normal.dist(0, 1))\n\n        self.distributions = [alpha, sigma, mu, b, Z, nb2, zip, w, nested_mix, Y_obs, pot]\n        self.deterministics_or_potentials = [mu, pot, pred]\n        # tuples of (formatting, include_params)\n        self.formats = [("plain", True), ("plain", False), ("latex", True), ("latex", False)]\n        self.expected = {\n            ("plain", True): [\n                r"alpha ~ Normal(0, 10)",\n                r"sigma ~ HalfNormal(0, 1)",\n                r"mu ~ Deterministic(f(beta, alpha))",\n                r"beta ~ Normal(0, 10)",\n                r"Z ~ MultivariateNormal(f(), f())",\n                r"nb_with_p_n ~ NegativeBinomial(10, nbp)",\n                r"zip ~ MarginalMixture(f(), DiracDelta(0), Poisson(5))",\n                r"w ~ Dirichlet(<constant>)",\n                (\n                    r"nested_mix ~ MarginalMixture(w, "\n                    r"MarginalMixture(f(), DiracDelta(0), Poisson(5)), "\n                    r"Censored(Bernoulli(0.5), -1, 1))"\n                ),\n                r"Y_obs ~ Normal(mu, sigma)",\n                r"pot ~ Potential(f(beta, alpha))",\n                r"pred ~ Deterministic(f(<normal>))",\n            ],\n            ("plain", False): [\n                r"alpha ~ Normal",\n                r"sigma ~ HalfNormal",\n                r"mu ~ Deterministic",\n                r"beta ~ Normal",\n                r"Z ~ MultivariateNormal",\n                r"nb_with_p_n ~ NegativeBinomial",\n                r"zip ~ MarginalMixture",\n                r"w ~ Dirichlet",\n                r"nested_mix ~ MarginalMixture",\n                r"Y_obs ~ Normal",\n                r"pot ~ Potential",\n                r"pred ~ Deterministic",\n            ],\n            ("latex", True): [\n                r"$\\text{alpha} \\sim \\operatorname{Normal}(0,~10)$",\n                r"$\\text{sigma} \\sim \\operatorname{HalfNormal}(0,~1)$",\n                r"$\\text{mu} \\sim \\operatorname{Deterministic}(f(\\text{beta},~\\text{alpha}))$",\n                r"$\\text{beta} \\sim \\operatorname{Normal}(0,~10)$",\n                r"$\\text{Z} \\sim \\operatorname{MultivariateNormal}(f(),~f())$",\n                r"$\\text{nb_with_p_n} \\sim \\operatorname{NegativeBinomial}(10,~\\text{nbp})$",\n                r"$\\text{zip} \\sim \\operatorname{MarginalMixture}(f(),~\\operatorname{DiracDelta}(0),~\\operatorname{Poisson}(5))$",\n                r"$\\text{w} \\sim \\operatorname{Dirichlet}(\\text{<constant>})$",\n                (\n                    r"$\\text{nested_mix} \\sim \\operatorname{MarginalMixture}(\\text{w},"\n                    r"~\\operatorname{MarginalMixture}(f(),~\\operatorname{DiracDelta}(0),~\\operatorname{Poisson}(5)),"\n                    r"~\\operatorname{Censored}(\\operatorname{Bernoulli}(0.5),~-1,~1))$"\n                ),\n                r"$\\text{Y_obs} \\sim \\operatorname{Normal}(\\text{mu},~\\text{sigma})$",\n                r"$\\text{pot} \\sim \\operatorname{Potential}(f(\\text{beta},~\\text{alpha}))$",\n                r"$\\text{pred} \\sim \\operatorname{Deterministic}(f(\\text{<normal>}))",\n            ],\n            ("latex", False): [\n                r"$\\text{alpha} \\sim \\operatorname{Normal}$",\n                r"$\\text{sigma} \\sim \\operatorname{HalfNormal}$",\n                r"$\\text{mu} \\sim \\operatorname{Deterministic}$",\n                r"$\\text{beta} \\sim \\operatorname{Normal}$",\n                r"$\\text{Z} \\sim \\operatorname{MultivariateNormal}$",\n                r"$\\text{nb_with_p_n} \\sim \\operatorname{NegativeBinomial}$",\n                r"$\\text{zip} \\sim \\operatorname{MarginalMixture}$",\n                r"$\\text{w} \\sim \\operatorname{Dirichlet}$",\n                r"$\\text{nested_mix} \\sim \\operatorname{MarginalMixture}$",\n                r"$\\text{Y_obs} \\sim \\operatorname{Normal}$",\n                r"$\\text{pot} \\sim \\operatorname{Potential}$",\n                r"$\\text{pred} \\sim \\operatorname{Deterministic}",\n            ],\n        }\n\n\nclass TestData(BaseTestStrAndLatexRepr):\n    def setup_class(self):\n        with Model() as self.model:\n            import pymc as pm\n\n            with pm.Model() as model:\n                a = pm.Normal("a", pm.Data("a_data", (2,)))\n                b = pm.Normal("b", pm.Data("b_data", (2, 3)))\n                c = pm.Normal("c", pm.Data("c_data", (2,)))\n                d = pm.Normal("d", pm.Data("d_data", (2, 3)))\n\n        self.distributions = [a, b, c, d]\n        # tuples of (formatting, include_params)\n        self.formats = [("plain", True), ("plain", False), ("latex", True), ("latex", False)]\n        self.expected = {\n            ("plain", True): [\n                r"a ~ Normal(2, 1)",\n                r"b ~ Normal(<shared>, 1)",\n                r"c ~ Normal(2, 1)",\n                r"d ~ Normal(<shared>, 1)",\n            ],\n            ("plain", False): [\n                r"a ~ Normal",\n                r"b ~ Normal",\n                r"c ~ Normal",\n                r"d ~ Normal",\n            ],\n            ("latex", True): [\n                r"$\\text{a} \\sim \\operatorname{Normal}(2,~1)$",\n                r"$\\text{b} \\sim \\operatorname{Normal}(\\text{<shared>},~1)$",\n                r"$\\text{c} \\sim \\operatorname{Normal}(2,~1)$",\n                r"$\\text{d} \\sim \\operatorname{Normal}(\\text{<shared>},~1)$",\n            ],\n            ("latex", False): [\n                r"$\\text{a} \\sim \\operatorname{Normal}$",\n                r"$\\text{b} \\sim \\operatorname{Normal}$",\n                r"$\\text{c} \\sim \\operatorname{Normal}$",\n                r"$\\text{d} \\sim \\operatorname{Normal}$",\n            ],\n        }\n\n\ndef test_model_latex_repr_three_levels_model():\n    with Model() as censored_model:\n        mu = Normal("mu", 0.0, 5.0)\n        sigma = HalfCauchy("sigma", 2.5)\n        normal_dist = Normal.dist(mu=mu, sigma=sigma)\n        censored_normal = Censored(\n            "censored_normal", normal_dist, lower=-2.0, upper=2.0, observed=[1, 0, 0.5]\n        )\n\n    latex_repr = censored_model.str_repr(formatting="latex")\n    expected = [\n        "$$",\n        "\\\\begin{array}{rcl}",\n        "\\\\text{mu} &\\\\sim & \\\\operatorname{Normal}(0,~5)\\\\\\\\\\\\text{sigma} &\\\\sim & "\n        "\\\\operatorname{HalfCauchy}(0,~2.5)\\\\\\\\\\\\text{censored_normal} &\\\\sim & "\n        "\\\\operatorname{Censored}(\\\\operatorname{Normal}(\\\\text{mu},~\\\\text{sigma}),~-2,~2)",\n        "\\\\end{array}",\n        "$$",\n    ]\n    assert [line.strip() for line in latex_repr.split("\\n")] == expected\n\n\ndef test_model_latex_repr_mixture_model():\n    with Model() as mix_model:\n        w = Dirichlet("w", [1, 1])\n        mix = Mixture("mix", w=w, comp_dists=[Normal.dist(0.0, 5.0), StudentT.dist(7.0)])\n\n    latex_repr = mix_model.str_repr(formatting="latex")\n    expected = [\n        "$$",\n        "\\\\begin{array}{rcl}",\n        "\\\\text{w} &\\\\sim & "\n        "\\\\operatorname{Dirichlet}(\\\\text{<constant>})\\\\\\\\\\\\text{mix} &\\\\sim & "\n        "\\\\operatorname{MarginalMixture}(\\\\text{w},~\\\\operatorname{Normal}(0,~5),~\\\\operatorname{StudentT}(7,~0,~1))",\n        "\\\\end{array}",\n        "$$",\n    ]\n    assert [line.strip() for line in latex_repr.split("\\n")] == expected\n\n\ndef test_model_repr_variables_without_monkey_patched_repr():\n    """Test that model repr does not rely on individual variables having the str_repr method monkey patched."""\n    x = normal(name="x")\n    assert not hasattr(x, "str_repr")\n\n    model = Model()\n    model.register_rv(x, "x")\n\n    str_repr = model.str_repr()\n    assert str_repr == "x ~ Normal(0, 1)"\n\n\ndef test_truncated_repr():\n    with Model() as model:\n        x = Truncated("x", Gamma.dist(1, 1), lower=0, upper=20)\n\n    str_repr = model.str_repr(include_params=False)\n    assert str_repr == "x ~ TruncatedGamma"\n\n\ndef test_custom_dist_repr():\n    with Model() as model:\n\n        def dist(mu, size):\n            return Normal.dist(mu, 1, size=size)\n\n        def random(rng, mu, size):\n            return rng.normal(mu, size=size)\n\n        x = CustomDist("x", 0, dist=dist, class_name="CustomDistNormal")\n        x = CustomDist("y", 0, random=random, class_name="CustomRandomNormal")\n\n    str_repr = model.str_repr(include_params=False)\n    assert str_repr == "\\n".join(["x ~ CustomDistNormal", "y ~ CustomRandomNormal"])\n',
        }
